import React, { useEffect, useState } from 'react';
import { Event, EventCategory } from '../types';
import { api } from '../services/api';
import EventCard from '../components/EventCard';
import { useLocationContext } from '../context/LocationContext';
import { Search, Filter, X, Calendar, Tag, DollarSign, Check, MapPin, Sparkles } from 'lucide-react';

const Home: React.FC = () => {
  const [events, setEvents] = useState<Event[]>([]);
  const [loading, setLoading] = useState(true);
  const [searchTerm, setSearchTerm] = useState('');
  const { selectedCity } = useLocationContext();

  // Filter States
  const [showFilters, setShowFilters] = useState(false);
  const [selectedTime, setSelectedTime] = useState<'all' | 'today' | 'tomorrow' | 'week' | 'weekend'>('all');
  const [selectedPrice, setSelectedPrice] = useState<'all' | 'free' | 'paid'>('all');
  const [selectedCategory, setSelectedCategory] = useState<'all' | EventCategory>('all');

  useEffect(() => {
    const fetchEvents = async () => {
      try {
        const data = await api.events.getAll();
        setEvents(data);
      } catch (error) {
        console.error("Failed to fetch events", error);
      } finally {
        setLoading(false);
      }
    };
    fetchEvents();
  }, []);

  // FILTER LOGIC
  const filteredEvents = events.filter(e => {
    if (selectedCity !== 'Tutte' && e.city !== selectedCity) return false;
    const lowerSearch = searchTerm.toLowerCase();
    const orgName = typeof e.organization === 'object' && e.organization !== null && 'name' in e.organization
      ? e.organization.name.toLowerCase() 
      : '';
    const matchesSearch = 
      e.title.toLowerCase().includes(lowerSearch) ||
      e.location.toLowerCase().includes(lowerSearch) ||
      orgName.includes(lowerSearch);
    if (!matchesSearch) return false;
    if (selectedCategory !== 'all' && e.category !== selectedCategory) return false;
    if (selectedPrice === 'free' && e.price > 0) return false;
    if (selectedPrice === 'paid' && e.price === 0) return false;
    if (selectedTime !== 'all') {
        const eventDate = new Date(e.date);
        const today = new Date();
        today.setHours(0,0,0,0);
        const tomorrow = new Date(today);
        tomorrow.setDate(today.getDate() + 1);
        const eventDateNoTime = new Date(eventDate);
        eventDateNoTime.setHours(0,0,0,0);
        if (selectedTime === 'today') {
            if (eventDateNoTime.getTime() !== today.getTime()) return false;
        }
        else if (selectedTime === 'tomorrow') {
            if (eventDateNoTime.getTime() !== tomorrow.getTime()) return false;
        }
        else if (selectedTime === 'week') {
            const nextWeek = new Date(today);
            nextWeek.setDate(today.getDate() + 7);
            if (eventDateNoTime < today || eventDateNoTime > nextWeek) return false;
        }
        else if (selectedTime === 'weekend') {
            const day = eventDate.getDay(); 
            const isWeekendDay = day === 0 || day === 5 || day === 6;
            const nextWeek = new Date(today);
            nextWeek.setDate(today.getDate() + 7);
            if (!isWeekendDay || eventDateNoTime > nextWeek || eventDateNoTime < today) return false;
        }
    }
    return true;
  });

  const clearFilters = () => {
      setSelectedTime('all');
      setSelectedPrice('all');
      setSelectedCategory('all');
  };

  const hasActiveFilters = selectedTime !== 'all' || selectedPrice !== 'all' || selectedCategory !== 'all';

  return (
    <div className="min-h-screen bg-[#020617] text-white pb-24 md:pb-0">
      {/* Hero Section */}
      <div className="bg-transparent py-10 md:py-24 relative overflow-hidden">
        {/* Background neon glows */}
        <div className="absolute inset-0 overflow-hidden pointer-events-none">
            <div className="absolute top-0 left-1/4 w-[500px] h-[500px] bg-indigo-600/20 rounded-full filter blur-[120px] animate-pulse"></div>
            <div className="absolute bottom-0 right-1/4 w-[500px] h-[500px] bg-purple-600/10 rounded-full filter blur-[100px]"></div>
            <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-full h-full bg-[url('https://www.transparenttextures.com/patterns/carbon-fibre.png')] opacity-10"></div>
        </div>

        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 text-center relative z-10">
          <div className="inline-flex items-center px-4 py-1.5 rounded-full bg-indigo-500/10 border border-indigo-500/20 text-indigo-400 text-[10px] md:text-xs font-black uppercase tracking-[0.2em] mb-4 md:mb-6 animate-bounce">
            <Sparkles className="w-3 h-3 mr-2" />
            University Life Reimagined
          </div>
          <h1 className="text-3xl md:text-7xl font-black mb-3 md:mb-4 tracking-tighter leading-tight bg-clip-text text-transparent bg-gradient-to-b from-white via-white to-indigo-300">
            {selectedCity === 'Tutte' ? 'Find Your Next Party' : `Eventi a ${selectedCity}`}
          </h1>
          <p className="text-sm md:text-xl text-gray-400 mb-8 md:mb-12 max-w-2xl mx-auto font-medium">
            {selectedCity === 'Tutte' 
              ? 'The official platform for university events. Exclusive parties, networking, and fun.'
              : `I migliori eventi universitari a ${selectedCity}. Feste, seminari e networking.`}
          </p>

          {/* Search Bar */}
          <div className="max-w-2xl mx-auto relative flex flex-col md:flex-row items-center gap-3">
            <div className="relative flex-grow w-full">
                <input
                  type="text"
                  placeholder="Search events..."
                  className="w-full pl-6 pr-12 py-3 md:py-5 rounded-xl md:rounded-2xl bg-white/5 backdrop-blur-md text-white border border-white/10 focus:border-indigo-500/50 focus:ring-4 focus:ring-indigo-500/10 outline-none transition-all placeholder-gray-500 font-medium text-sm md:text-base"
                  value={searchTerm}
                  onChange={(e) => setSearchTerm(e.target.value)}
                />
                <div className="absolute right-4 top-1/2 transform -translate-y-1/2">
                    <Search className="h-5 w-5 md:h-6 md:w-6 text-gray-500" />
                </div>
            </div>
            <button 
                onClick={() => setShowFilters(!showFilters)}
                className={`w-full md:w-auto px-6 py-3 md:px-8 md:py-5 rounded-xl md:rounded-2xl font-black text-[10px] md:text-sm uppercase tracking-widest transition-all shadow-xl flex items-center justify-center ${showFilters || hasActiveFilters ? 'bg-indigo-600 text-white shadow-indigo-500/40 border border-indigo-400/50' : 'bg-white/5 border border-white/10 text-gray-300 hover:bg-white/10'}`}
            >
                <Filter className="h-4 w-4 md:h-5 md:w-5 mr-2" />
                Filters
            </button>
          </div>
        </div>
      </div>

      {/* Filter Panel */}
      {showFilters && (
          <div className="bg-slate-900/80 backdrop-blur-xl border-y border-white/10 shadow-2xl animate-in slide-in-from-top-2 duration-300 sticky top-16 z-40">
              <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
                  <div className="flex justify-between items-center mb-8">
                      <h3 className="text-xs font-black text-indigo-400 uppercase tracking-[0.3em]">Precision Search</h3>
                      <button onClick={clearFilters} className="text-sm font-bold text-gray-400 hover:text-white transition">
                          Reset All
                      </button>
                  </div>

                  <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
                      {/* Time Filter */}
                      <div>
                          <label className="block text-xs font-black text-gray-500 mb-4 uppercase tracking-widest flex items-center">
                              <Calendar className="w-4 h-4 mr-2 text-indigo-500" /> Date
                          </label>
                          <div className="flex flex-wrap gap-2">
                              {['all', 'today', 'tomorrow', 'week', 'weekend'].map((t) => (
                                  <button
                                    key={t}
                                    onClick={() => setSelectedTime(t as any)}
                                    className={`px-4 py-2 rounded-xl text-xs font-bold border transition-all ${selectedTime === t ? 'bg-indigo-600 border-indigo-400 text-white shadow-[0_0_15px_rgba(99,102,241,0.4)]' : 'bg-white/5 border-white/10 text-gray-400 hover:border-indigo-500/30 hover:text-white'}`}
                                  >
                                      {t === 'all' ? 'Anytime' : t.charAt(0).toUpperCase() + t.slice(1)}
                                  </button>
                              ))}
                          </div>
                      </div>

                      {/* Category Filter */}
                      <div>
                          <label className="block text-xs font-black text-gray-500 mb-4 uppercase tracking-widest flex items-center">
                              <Tag className="w-4 h-4 mr-2 text-indigo-500" /> Genre
                          </label>
                          <div className="flex flex-wrap gap-2">
                              <button
                                onClick={() => setSelectedCategory('all')}
                                className={`px-4 py-2 rounded-xl text-xs font-bold border transition-all ${selectedCategory === 'all' ? 'bg-indigo-600 border-indigo-400 text-white shadow-[0_0_15px_rgba(99,102,241,0.4)]' : 'bg-white/5 border-white/10 text-gray-400 hover:border-indigo-500/30 hover:text-white'}`}
                              >
                                  All
                              </button>
                              {Object.values(EventCategory).map((cat) => (
                                  <button
                                    key={cat}
                                    onClick={() => setSelectedCategory(cat)}
                                    className={`px-4 py-2 rounded-xl text-xs font-bold border transition-all ${selectedCategory === cat ? 'bg-indigo-600 border-indigo-400 text-white shadow-[0_0_15px_rgba(99,102,241,0.4)]' : 'bg-white/5 border-white/10 text-gray-400 hover:border-indigo-500/30 hover:text-white'}`}
                                  >
                                      {cat}
                                  </button>
                              ))}
                          </div>
                      </div>

                      {/* Price Filter */}
                      <div>
                          <label className="block text-xs font-black text-gray-500 mb-4 uppercase tracking-widest flex items-center">
                              <DollarSign className="w-4 h-4 mr-2 text-indigo-500" /> Pricing
                          </label>
                          <div className="flex flex-wrap gap-2">
                              {[
                                  { id: 'all', label: 'Any' }, 
                                  { id: 'free', label: 'Free Only' }, 
                                  { id: 'paid', label: 'Paid Only' }
                              ].map((p) => (
                                  <button
                                    key={p.id}
                                    onClick={() => setSelectedPrice(p.id as any)}
                                    className={`px-4 py-2 rounded-xl text-xs font-bold border transition-all ${selectedPrice === p.id ? 'bg-indigo-600 border-indigo-400 text-white shadow-[0_0_15px_rgba(99,102,241,0.4)]' : 'bg-white/5 border-white/10 text-gray-400 hover:border-indigo-500/30 hover:text-white'}`}
                                  >
                                      {p.label}
                                  </button>
                              ))}
                          </div>
                      </div>
                  </div>
              </div>
          </div>
      )}

      {/* Active Filters Chips */}
      {(hasActiveFilters || selectedCity !== 'Tutte') && (
          <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-4 flex items-center space-x-2 overflow-x-auto scrollbar-hide">
              <span className="text-[8px] md:text-[10px] font-black text-gray-600 uppercase tracking-widest mr-1 shrink-0">Active:</span>
              {selectedCity !== 'Tutte' && (
                  <span className="inline-flex items-center px-3 py-1 rounded-full text-[9px] md:text-[11px] font-black bg-indigo-500/10 text-indigo-400 border border-indigo-500/20 uppercase tracking-wider shrink-0">
                      <MapPin className="w-3 h-3 mr-1" />
                      {selectedCity}
                  </span>
              )}
              {selectedTime !== 'all' && (
                  <span className="inline-flex items-center px-3 py-1 rounded-full text-[9px] md:text-[11px] font-black bg-indigo-500/10 text-indigo-400 border border-indigo-500/20 uppercase tracking-wider shrink-0">
                      {selectedTime}
                      <button onClick={() => setSelectedTime('all')} className="ml-1.5 hover:text-white transition"><X className="w-3 h-3"/></button>
                  </span>
              )}
              {selectedCategory !== 'all' && (
                  <span className="inline-flex items-center px-3 py-1 rounded-full text-[9px] md:text-[11px] font-black bg-indigo-500/10 text-indigo-400 border border-indigo-500/20 uppercase tracking-wider shrink-0">
                      {selectedCategory}
                      <button onClick={() => setSelectedCategory('all')} className="ml-1.5 hover:text-white transition"><X className="w-3 h-3"/></button>
                  </span>
              )}
              {selectedPrice !== 'all' && (
                  <span className="inline-flex items-center px-3 py-1 rounded-full text-[9px] md:text-[11px] font-black bg-indigo-500/10 text-indigo-400 border border-indigo-500/20 uppercase tracking-wider shrink-0">
                      {selectedPrice}
                      <button onClick={() => setSelectedPrice('all')} className="ml-1.5 hover:text-white transition"><X className="w-3 h-3"/></button>
                  </span>
              )}
              <button onClick={clearFilters} className="text-[8px] md:text-[10px] font-black text-gray-600 hover:text-red-400 uppercase tracking-widest ml-auto transition shrink-0">Clear All</button>
          </div>
      )}

      {/* Events Grid */}
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-6 md:py-12">
        <div className="flex justify-between items-center mb-6 md:mb-10">
          <h2 className="text-xl md:text-3xl font-black text-white tracking-tight">
              {searchTerm ? 'Search Results' : 'Trending Events'}
              <span className="ml-2 md:ml-4 text-[10px] md:text-sm font-bold text-gray-600">({filteredEvents.length})</span>
          </h2>
        </div>

        {loading ? (
          <div className="grid grid-cols-2 md:grid-cols-2 lg:grid-cols-3 gap-3 md:gap-8">
             {[1, 2, 3, 4].map(i => (
               <div key={i} className="bg-white/5 border border-white/10 rounded-xl md:rounded-2xl h-[250px] md:h-[450px] animate-pulse"></div>
             ))}
          </div>
        ) : (
          <div className="grid grid-cols-2 md:grid-cols-2 lg:grid-cols-3 gap-3 md:gap-8">
            {filteredEvents.length > 0 ? (
              filteredEvents.map(event => (
                <EventCard key={event._id} event={event} />
              ))
            ) : (
              <div className="col-span-full py-20 md:py-32 text-center glass-card rounded-2xl md:rounded-3xl border-dashed">
                <div className="bg-indigo-500/10 border border-indigo-500/20 rounded-full w-14 h-14 md:w-20 md:h-20 flex items-center justify-center mx-auto mb-4 md:mb-6 shadow-[0_0_30px_rgba(99,102,241,0.1)]">
                    <Search className="w-6 h-6 md:w-10 md:h-10 text-indigo-400" />
                </div>
                <h3 className="text-lg md:text-2xl font-black text-white mb-2">No matching events</h3>
                <p className="text-xs md:text-gray-500 font-medium">
                  {selectedCity !== 'Tutte' 
                    ? `Non ci sono eventi al momento a ${selectedCity}.`
                    : 'Try adjusting your filters or search terms.'}
                </p>
                <button onClick={clearFilters} className="mt-6 md:mt-8 bg-indigo-600 hover:bg-indigo-700 text-white px-6 py-2.5 md:px-8 md:py-3 rounded-lg md:rounded-xl font-bold transition shadow-lg text-xs md:text-base">Clear all filters</button>
              </div>
            )}
          </div>
        )}
      </div>
    </div>
  );
};

export default Home;

import React from 'react';
import { Link } from 'react-router-dom';
import { Calendar, MapPin, Users, Flame, Heart } from 'lucide-react';
import { Event, UserRole } from '../types';
import { useAuth } from '../context/AuthContext';

interface EventCardProps {
  event: Event;
}

const EventCard: React.FC<EventCardProps> = ({ event }) => {
  const { user, toggleFavorite } = useAuth();

  const eventDate = new Date(event.date).toLocaleDateString('it-IT', {
    weekday: 'short',
    day: 'numeric',
    month: 'short',
  });

  // FIX: Strict Integer Math for Price Display
  const priceInCents = Math.round(Number(event.price) * 100);
  const isFree = priceInCents === 0;
  const feeInCents = isFree ? 0 : 40;
  const totalInCents = priceInCents + feeInCents;
  const finalPrice = totalInCents / 100;

  const soldRatio = event.ticketsSold / event.maxCapacity;
  const isSoldOut = soldRatio >= 1;
  const isAlmostSoldOut = soldRatio >= 0.6 && !isSoldOut;

  const organizationId = typeof event.organization === 'string' 
    ? event.organization 
    : event.organization?._id;

  const isOwner = user && organizationId && user._id === organizationId;
  const showExactNumbers = isOwner;

  const isFavorite = user?.favorites?.includes(event._id) || false;

  const handleFavoriteClick = (e: React.MouseEvent) => {
      e.preventDefault(); 
      e.stopPropagation();
      if (user && user.role === UserRole.STUDENTE) {
          toggleFavorite(event._id);
      } else if (!user) {
          alert("Accedi come studente per salvare i preferiti.");
      }
  };

  const handleImageError = (e: React.SyntheticEvent<HTMLImageElement>) => {
    e.currentTarget.src = "https://picsum.photos/800/400?random=999"; 
  };

  return (
    <Link to={`/events/${event._id}`} className="group relative block h-full">
      <div className="bg-white/5 backdrop-blur-md rounded-xl md:rounded-2xl shadow-xl overflow-hidden hover:shadow-[0_0_30px_rgba(99,102,241,0.2)] hover:border-indigo-500/30 transition-all duration-500 border border-white/10 h-full flex flex-col">
        <div className="relative h-32 md:h-48 overflow-hidden">
          <img
            src={event.image}
            alt={event.title}
            onError={handleImageError}
            className="w-full h-full object-cover transform group-hover:scale-110 transition-transform duration-700"
          />
          <div className="absolute top-2 right-2 md:top-4 md:right-4 flex gap-1.5 md:gap-2">
               {/* Favorite Button (Students Only) */}
               {(!user || user.role === UserRole.STUDENTE) && (
                   <button 
                        onClick={handleFavoriteClick}
                        className="bg-black/40 backdrop-blur-md p-1.5 md:p-2 rounded-full shadow-lg hover:scale-110 active:scale-95 transition-all z-10 border border-white/10"
                   >
                       <Heart 
                          className={`w-3.5 h-3.5 md:w-5 md:h-5 transition-colors ${isFavorite ? 'fill-neon-pink text-neon-pink' : 'text-white/70 hover:text-neon-pink'}`} 
                        />
                   </button>
               )}
               {/* Owner sees favorite count */}
               {isOwner && (
                   <div className="bg-black/60 backdrop-blur-md px-2 md:px-3 py-0.5 md:py-1 rounded-full text-neon-pink font-bold text-[9px] md:text-sm shadow-sm flex items-center border border-white/10">
                       <Heart className="w-2.5 h-2.5 md:w-3 h-3 mr-1 fill-neon-pink" />
                       {event.favoritesCount || 0}
                   </div>
               )}
               <div className="bg-indigo-600/90 backdrop-blur-md px-2.5 py-1 md:px-4 md:py-1.5 rounded-full text-white font-black text-[9px] md:text-sm shadow-[0_0_15px_rgba(79,70,229,0.5)] flex items-center border border-white/20">
                    {isFree ? 'FREE' : `€${finalPrice.toFixed(2)}`}
               </div>
          </div>

          {/* Subtle gradient overlay */}
          <div className="absolute inset-0 bg-gradient-to-t from-slate-900/80 via-transparent to-transparent pointer-events-none"></div>
        </div>

        <div className="p-3 md:p-6 flex-1 flex flex-col">
          <div className="text-[8px] md:text-[10px] font-black text-indigo-400 mb-1 md:mb-2 uppercase tracking-[0.2em] truncate">
            {typeof event.organization === 'string' ? 'Association' : (event.organization?.name || 'Association')}
          </div>
          <h3 className="text-sm md:text-xl font-extrabold text-white mb-1.5 md:mb-3 group-hover:text-indigo-400 transition-colors leading-tight line-clamp-2">
            {event.title}
          </h3>
          <p className="text-gray-400 text-[10px] md:text-sm mb-3 md:mb-6 line-clamp-1 md:line-clamp-2 flex-1 leading-relaxed font-medium hidden xs:block">
            {event.description}
          </p>

          <div className="space-y-1.5 md:space-y-3 text-[9px] md:text-sm text-gray-400 mt-auto pt-2 md:pt-5 border-t border-white/5">
            <div className="flex items-center">
              <Calendar className="h-3 w-3 md:h-4 md:w-4 mr-2 md:mr-3 text-indigo-400/80 shrink-0" />
              <span className="font-semibold truncate">{eventDate} • {event.time}</span>
            </div>
            <div className="flex items-center">
              <MapPin className="h-3 w-3 md:h-4 md:w-4 mr-2 md:mr-3 text-indigo-400/80 shrink-0" />
              <span className="truncate font-medium">{event.location}</span>
            </div>
            <div className="flex items-center">
              <Users className="h-3 w-3 md:h-4 md:w-4 mr-2 md:mr-3 text-indigo-400/80 shrink-0" />
              <span className={`font-bold ${isSoldOut ? 'text-red-400' : 'text-gray-300'} truncate`}>
                {showExactNumbers 
                  ? `${event.ticketsSold}/${event.maxCapacity}`
                  : isSoldOut 
                    ? 'SOLD OUT' 
                    : isAlmostSoldOut 
                      ? 'Ultimi posti!' 
                      : 'Disponibile'}
              </span>
            </div>
            {isAlmostSoldOut && !isSoldOut && (
               <div className="flex items-center text-orange-400 text-[8px] md:text-[10px] font-black mt-1 uppercase tracking-widest animate-pulse">
                 <Flame className="h-2.5 w-2.5 md:h-3 md:w-3 mr-1.5" />
                 Selling fast!
               </div>
            )}
          </div>
        </div>
      </div>
    </Link>
  );
};

export default EventCard;

import React, { useState, useEffect } from 'react';
import { useAuth } from '../context/AuthContext';
import { api } from '../services/api';
import { UserRole, EventCategory, Event, User, UNIVERSITY_LOCATIONS } from '../types';
import { useNavigate, useSearchParams, Link } from 'react-router-dom';
import { 
    AlertTriangle, CheckCircle, Plus, DollarSign, Image as ImageIcon, Users, List, X, Tag, Clock, 
    ShieldCheck, Lock, Info, Upload, FileText, TrendingUp, Briefcase, Ticket, LayoutDashboard, Calendar, Settings, GraduationCap, UserPlus, Key, Trash2, MapPin, Sparkles, BookOpen
} from 'lucide-react';

const Dashboard: React.FC = () => {
  const { user, refreshUser } = useAuth();
  const navigate = useNavigate();
  const [searchParams, setSearchParams] = useSearchParams();

  // Tab State: 'overview', 'create', or 'staff'
  const [activeTab, setActiveTab] = useState<'overview' | 'create' | 'staff'>('overview');

  const [isConnecting, setIsConnecting] = useState(false);

  // Overview Data State
  const [assocEvents, setAssocEvents] = useState<Event[]>([]);
  const [loadingEvents, setLoadingEvents] = useState(false);

  // Event Form State
  const [title, setTitle] = useState('');
  const [description, setDescription] = useState('');
  const [price, setPrice] = useState('0');
  const [date, setDate] = useState('');
  const [time, setTime] = useState('22:00');
  const [location, setLocation] = useState('');
  const [selectedRegion, setSelectedRegion] = useState('');
  const [city, setCity] = useState('');
  const [image, setImage] = useState('');
  const [maxCapacity, setMaxCapacity] = useState('100');
  const [category, setCategory] = useState<EventCategory>(EventCategory.PARTY);

  // Advanced Options
  const [requiresAcademicData, setRequiresAcademicData] = useState(false); 
  const [scanType, setScanType] = useState<'entry_only' | 'entry_exit'>('entry_only');

  // PR Lists State
  const [prLists, setPrLists] = useState<string[]>([]);
  const [currentPrInput, setCurrentPrInput] = useState('');

  const [creatingEvent, setCreatingEvent] = useState(false);
  const [targetStatus, setTargetStatus] = useState<'active' | 'draft'>('active');

  // Staff Management State
  const [staffEmail, setStaffEmail] = useState('');
  const [staffPassword, setStaffPassword] = useState('');
  const [isManagingStaff, setIsManagingStaff] = useState(false);
  const [staffList, setStaffList] = useState<User[]>([]);
  const [loadingStaff, setLoadingStaff] = useState(false);

  // Reset city if region changes
  useEffect(() => {
    setCity('');
  }, [selectedRegion]);

  // Handle Query Param for Tab
  useEffect(() => {
    const tabParam = searchParams.get('tab');
    if (tabParam === 'create') {
        setActiveTab('create');
    } else if (tabParam === 'staff') {
        setActiveTab('staff');
    } else {
        setActiveTab('overview');
    }
  }, [searchParams]);

  // Fetch Events for Overview
  useEffect(() => {
    if (user && user.role === UserRole.ASSOCIAZIONE) {
      setLoadingEvents(true);
      api.events.getByOrgId(user._id)
        .then(setAssocEvents)
        .catch(console.error)
        .finally(() => setLoadingEvents(false));
    }
  }, [user]);

  // Fetch Staff Accounts
  useEffect(() => {
    if (activeTab === 'staff' && user && user.role === UserRole.ASSOCIAZIONE) {
        fetchStaff();
    }
  }, [activeTab, user]);

  const fetchStaff = async () => {
    setLoadingStaff(true);
    try {
        const data = await api.auth.getStaffAccounts();
        setStaffList(data);
    } catch (e) {
        console.error("Fetch staff error", e);
    } finally {
        setLoadingStaff(false);
    }
  };

  if (!user || user.role !== UserRole.ASSOCIAZIONE) {
    return <div className="p-8 bg-gray-900 text-white min-h-screen">Access Denied</div>;
  }

  // Calculate Stats
  const totalEvents = assocEvents.length;
  const totalTicketsSold = assocEvents.reduce((acc, curr) => acc + curr.ticketsSold, 0);
  const totalRevenue = assocEvents.reduce((acc, curr) => acc + (curr.ticketsSold * curr.price), 0);

  const handleTabChange = (tab: 'overview' | 'create' | 'staff') => {
      setActiveTab(tab);
      setSearchParams(tab !== 'overview' ? { tab } : {});
  };

  const handleStripeConnect = async () => {
    setIsConnecting(true);
    try {
      const link = await api.stripe.createConnectAccount(user._id);
      if (link) {
          window.location.href = link;
      } else {
           const confirmed = window.confirm("Simulating Stripe Onboarding. Click OK to finish.");
           if(confirmed) {
               await api.stripe.finalizeOnboarding(user._id);
               refreshUser();
           }
      }
    } catch (error) {
      console.error(error);
      alert("Failed to connect Stripe");
    } finally {
      setIsConnecting(false);
    }
  };

  const handleAddPrList = () => {
      if (currentPrInput.trim() && !prLists.includes(currentPrInput.trim())) {
          setPrLists([...prLists, currentPrInput.trim()]);
          setCurrentPrInput('');
      }
  };

  const handleRemovePrList = (listToRemove: string) => {
      setPrLists(prLists.filter(list => list !== listToRemove));
  };

  const handleImageUpload = () => {
    const widget = window.cloudinary.createUploadWidget(
      {
        cloudName: 'db3bj2bgg',
        uploadPreset: 'wii81qid',
        sources: ['local', 'url', 'camera', 'instagram'],
        multiple: false,
        maxFiles: 1,
        clientAllowedFormats: ["image"],
      },
      (error: any, result: any) => {
        if (!error && result && result.event === "success") {
          setImage(result.info.secure_url);
        }
      }
    );
    widget.open();
  };

  const handleCreateEvent = async (e: React.FormEvent) => {
    e.preventDefault();
    const cleanPriceStr = (user.stripeOnboardingComplete ? price : '0').toString().replace(',', '.');
    const tempPrice = parseFloat(cleanPriceStr);
    const numericPrice = isNaN(tempPrice) ? 0 : Number(tempPrice.toFixed(2));

    if (isNaN(numericPrice) || numericPrice < 0) {
        alert("Prezzo non valido.");
        return;
    }

    if (!image) {
        alert("Per favore carica un'immagine per l'evento.");
        return;
    }

    if (!city) {
        alert("Per favore seleziona una città universitaria.");
        return;
    }

    setCreatingEvent(true);
    try {
        const newEvent = await api.events.create({
            title,
            description,
            longDescription: description,
            date,
            time,
            location,
            city,
            image,
            maxCapacity: parseInt(maxCapacity),
            price: numericPrice,
            category,
            prLists,
            status: targetStatus,
            requiresMatricola: requiresAcademicData, 
            requiresCorsoStudi: requiresAcademicData, 
            scanType
        }, user);

        if (targetStatus === 'draft') {
            alert("Bozza salvata con successo!");
            navigate(`/events/${newEvent._id}`);
        } else {
            alert("Evento pubblicato con successo!");
            navigate('/');
        }
    } catch (e: any) {
        console.error(e);
        alert("Errore creazione evento: " + (e.message || "Unknown"));
    } finally {
        setCreatingEvent(false);
    }
  };

  const handleManageStaff = async (e: React.FormEvent) => {
      e.preventDefault();
      if (!staffEmail || !staffPassword) return;

      setIsManagingStaff(true);
      try {
          await api.auth.createStaffAccount({ email: staffEmail, password: staffPassword });
          alert("Account Staff gestito con successo! Fornisci queste credenziali al tuo personale per lo scanner.");
          setStaffEmail('');
          setStaffPassword('');
          fetchStaff();
      } catch (e: any) {
          alert("Errore: " + e.message);
      } finally {
          setIsManagingStaff(false);
      }
  };

  const handleDeleteStaff = async (id: string) => {
    if (!window.confirm("Sei sicuro di voler eliminare questo account staff?")) return;
    try {
        await api.auth.deleteStaffAccount(id);
        setStaffList(staffList.filter(s => s._id !== id));
    } catch (e: any) {
        alert("Errore: " + e.message);
    }
  };

  return (
    <div className="min-h-screen bg-gray-900 text-white py-8 px-4 sm:px-6 lg:px-8">
       <div className="max-w-5xl mx-auto space-y-6">

           {/* Header & Tab Switcher */}
           <div className="flex flex-col md:flex-row justify-between items-center gap-4">
               <div>
                   <h1 className="text-3xl font-bold text-white">Dashboard Associazione</h1>
                   <p className="text-gray-400 text-sm mt-1">Benvenuto, {user.name}.</p>
               </div>

               {/* Tab Switcher */}
               <div className="bg-gray-800 p-1 rounded-xl shadow-sm border border-gray-700 flex">
                   <button
                       onClick={() => handleTabChange('overview')}
                       className={`px-4 py-2 rounded-lg text-sm font-medium transition flex items-center ${activeTab === 'overview' ? 'bg-indigo-900 text-indigo-100' : 'text-gray-400 hover:bg-gray-700'}`}
                   >
                       <LayoutDashboard className="w-4 h-4 mr-2" />
                       Panoramica
                   </button>
                   <button
                       onClick={() => handleTabChange('create')}
                       className={`px-4 py-2 rounded-lg text-sm font-medium transition flex items-center ${activeTab === 'create' ? 'bg-indigo-900 text-indigo-100' : 'text-gray-400 hover:bg-gray-700'}`}
                   >
                       <Plus className="w-4 h-4 mr-2" />
                       Crea Evento
                   </button>
                   <button
                       onClick={() => handleTabChange('staff')}
                       className={`px-4 py-2 rounded-lg text-sm font-medium transition flex items-center ${activeTab === 'staff' ? 'bg-indigo-900 text-indigo-100' : 'text-gray-400 hover:bg-gray-700'}`}
                   >
                       <Users className="w-4 h-4 mr-2" />
                       Staff
                   </button>
               </div>
           </div>

           {/* PANORAMICA */}
           {activeTab === 'overview' && (
               <div className="space-y-6 animate-in fade-in slide-in-from-bottom-2 duration-300">
                   <div className={`bg-gray-800 rounded-xl p-6 shadow-sm border-l-4 ${user.stripeOnboardingComplete ? 'border-green-500' : 'border-blue-500'}`}>
                       <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
                           <div className="flex items-start md:items-center">
                               {user.stripeOnboardingComplete ? (
                                   <div className="bg-green-900/30 p-3 rounded-full mr-4 shrink-0">
                                       <CheckCircle className="w-6 h-6 text-green-400" />
                                   </div>
                               ) : (
                                   <div className="bg-blue-900/30 p-3 rounded-full mr-4 shrink-0">
                                       <DollarSign className="w-6 h-6 text-blue-400" />
                                   </div>
                               )}
                               <div>
                                   <h2 className="text-xl font-bold text-white">Stato Pagamenti</h2>
                                   <p className="text-gray-400 text-sm">
                                       {user.stripeOnboardingComplete 
                                           ? "Il tuo account Stripe è attivo. Puoi ricevere pagamenti." 
                                           : "Connetti Stripe per poter vendere Voucher a pagamento."}
                                   </p>
                               </div>
                           </div>
                           {!user.stripeOnboardingComplete && (
                               <button 
                                   onClick={handleStripeConnect}
                                   disabled={isConnecting}
                                   className="bg-indigo-600 hover:bg-indigo-700 text-white px-6 py-2 rounded-lg font-bold transition shadow-md disabled:opacity-50 whitespace-nowrap"
                               >
                                   {isConnecting ? 'Connessione...' : 'Connetti Stripe'}
                               </button>
                           )}
                       </div>
                   </div>

                   <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                        <div className="bg-gray-800 rounded-xl shadow-sm p-6 flex items-center border border-gray-700">
                            <div className="p-3 rounded-full bg-indigo-900/30 text-indigo-400 mr-4">
                                <TrendingUp className="w-6 h-6" />
                            </div>
                            <div>
                                <p className="text-gray-400 text-sm font-medium">Totale Ricavi</p>
                                <p className="text-2xl font-bold text-white">€{totalRevenue.toFixed(2)}</p>
                            </div>
                        </div>
                        <div className="bg-gray-800 rounded-xl shadow-sm p-6 flex items-center border border-gray-700">
                            <div className="p-3 rounded-full bg-green-900/30 text-green-400 mr-4">
                                <Ticket className="w-6 h-6" />
                            </div>
                            <div>
                                <p className="text-gray-400 text-sm font-medium">Biglietti Venduti</p>
                                <p className="text-2xl font-bold text-white">{totalTicketsSold}</p>
                            </div>
                        </div>
                        <div className="bg-gray-800 rounded-xl shadow-sm p-6 flex items-center border border-gray-700">
                            <div className="p-3 rounded-full bg-orange-900/30 text-orange-400 mr-4">
                                <Briefcase className="w-6 h-6" />
                            </div>
                            <div>
                                <p className="text-gray-400 text-sm font-medium">Eventi Creati</p>
                                <p className="text-2xl font-bold text-white">{totalEvents}</p>
                            </div>
                        </div>
                   </div>

                   <div className="bg-gray-800 rounded-2xl shadow-sm p-6 md:p-8 border border-gray-700">
                        <div className="flex justify-between items-center mb-6">
                             <h2 className="text-xl font-bold text-white flex items-center">
                                <Briefcase className="w-6 h-6 mr-2 text-indigo-400" />
                                I Tuoi Eventi
                            </h2>
                        </div>

                        {loadingEvents ? (
                            <div className="text-center py-8 text-gray-400">Caricamento eventi...</div>
                        ) : assocEvents.length > 0 ? (
                            <div className="divide-y divide-gray-700">
                                {assocEvents.map(event => (
                                    <div key={event._id} className="py-4 flex flex-col md:flex-row md:items-center justify-between group gap-4">
                                        <div className="flex items-center">
                                            <div className="w-12 h-12 bg-gray-700 rounded-lg mr-4 overflow-hidden flex-shrink-0 border border-gray-600">
                                                <img src={event.image} className="w-full h-full object-cover" alt="" onError={(e) => (e.currentTarget.style.display = 'none')}/>
                                            </div>
                                            <div>
                                                <div className="flex items-center gap-2">
                                                    <h3 className="font-bold text-white group-hover:text-indigo-400 transition line-clamp-1">{event.title}</h3>
                                                    {event.status === 'draft' && (
                                                        <span className="bg-yellow-900/30 text-yellow-500 text-[10px] px-2 py-0.5 rounded font-bold uppercase">
                                                            BOZZA
                                                        </span>
                                                    )}
                                                </div>
                                                <div className="flex items-center text-xs text-gray-400 mt-1">
                                                    <Calendar className="w-3 h-3 mr-1" />
                                                    {new Date(event.date).toLocaleDateString()} • {event.city}
                                                </div>
                                            </div>
                                        </div>
                                        <div className="flex items-center justify-between md:justify-end gap-4 w-full md:w-auto">
                                            <div className="text-right">
                                                <div className="font-mono font-medium text-white text-sm">
                                                    {event.ticketsSold}/{event.maxCapacity}
                                                </div>
                                                <div className="text-xs text-green-400 font-semibold mt-1">
                                                    +€{(event.ticketsSold * event.price).toFixed(2)}
                                                </div>
                                            </div>
                                            <div className="flex gap-2">
                                                <Link 
                                                    to={`/events/${event._id}/attendees`}
                                                    className="px-3 py-1.5 bg-gray-700 hover:bg-gray-600 text-gray-200 rounded-lg text-xs font-bold transition flex items-center border border-gray-600"
                                                >
                                                    <Users className="w-3 h-3 mr-1" />
                                                    Lista
                                                </Link>
                                                <Link 
                                                    to={`/events/${event._id}`} 
                                                    className="px-3 py-1.5 bg-indigo-900/40 hover:bg-indigo-900/60 text-indigo-400 rounded-lg text-xs font-bold transition border border-indigo-900/50"
                                                >
                                                    Gestisci
                                                </Link>
                                            </div>
                                        </div>
                                    </div>
                                ))}
                            </div>
                        ) : (
                            <div className="text-center py-12 bg-gray-900 rounded-xl border border-dashed border-gray-700">
                                <p className="text-gray-400 mb-4">Non hai ancora creato nessun evento.</p>
                                <button onClick={() => handleTabChange('create')} className="bg-gray-800 border border-gray-700 px-4 py-2 rounded-lg text-sm font-medium hover:bg-gray-700 text-white">
                                    Inizia ora
                                </button>
                            </div>
                        )}
                   </div>
               </div>
           )}

           {/* CREA EVENTO */}
           {activeTab === 'create' && (
               <div className="animate-in fade-in slide-in-from-bottom-2 duration-300">
                   {!user.isVerified ? (
                        <div className="bg-yellow-900/10 border border-yellow-900/30 rounded-xl p-8 text-center shadow-sm">
                            <div className="w-16 h-16 bg-yellow-900/20 rounded-full flex items-center justify-center mx-auto mb-4">
                                <ShieldCheck className="w-8 h-8 text-yellow-500" />
                            </div>
                            <h2 className="text-xl font-bold text-white mb-2">Account in attesa di approvazione</h2>
                            <p className="text-gray-400 max-w-lg mx-auto mb-6">
                                Il nostro team sta verificando i dati della tua associazione. 
                            </p>
                        </div>
                   ) : (
                       <div className="bg-gray-800 rounded-xl shadow-lg overflow-hidden border border-gray-700">
                           <div className="bg-indigo-900/30 p-6 text-white border-b border-gray-700">
                               <h2 className="text-xl font-bold flex items-center text-indigo-400">
                                   <Plus className="w-6 h-6 mr-2" />
                                   Crea Nuovo Evento
                               </h2>
                           </div>

                           <form onSubmit={handleCreateEvent} className="p-6 md:p-8 space-y-6">
                               <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                                   <div className="md:col-span-2">
                                       <label className="block text-sm font-medium text-gray-300 mb-1">Titolo Evento</label>
                                       <input 
                                           type="text" 
                                           value={title} 
                                           onChange={e => setTitle(e.target.value)} 
                                           className="w-full px-4 py-2 bg-gray-700 border border-gray-600 rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none text-white placeholder-gray-400"
                                           required
                                           placeholder="Es. Halloween Party 2025"
                                       />
                                   </div>
                                   <div>
                                       <label className="block text-sm font-medium text-gray-300 mb-1 flex items-center"><Tag className="w-4 h-4 mr-1 text-indigo-400"/> Categoria</label>
                                       <select 
                                           value={category}
                                           onChange={e => setCategory(e.target.value as EventCategory)}
                                           className="w-full px-4 py-2 bg-gray-700 border border-gray-600 rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none text-white"
                                       >
                                           {Object.values(EventCategory).map(c => (
                                               <option key={c} value={c}>{c}</option>
                                           ))}
                                       </select>
                                   </div>
                               </div>

                               <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                                   <div>
                                       <label className="block text-sm font-medium text-gray-300 mb-1 flex items-center"><Clock className="w-4 h-4 mr-1 text-indigo-400"/> Data</label>
                                       <input 
                                           type="date" 
                                           value={date} 
                                           onChange={e => setDate(e.target.value)} 
                                           className="w-full px-4 py-2 bg-gray-700 border border-gray-600 rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none text-white"
                                           required
                                       />
                                   </div>
                                   <div>
                                       <label className="block text-sm font-medium text-gray-300 mb-1">Ora</label>
                                       <input 
                                           type="time" 
                                           value={time} 
                                           onChange={e => setTime(e.target.value)} 
                                           className="w-full px-4 py-2 bg-gray-700 border border-gray-600 rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none text-white"
                                           required
                                       />
                                   </div>
                                   <div className="grid grid-cols-1 gap-2">
                                       <div>
                                           <label className="block text-sm font-medium text-gray-300 mb-1">Regione</label>
                                           <select 
                                               value={selectedRegion}
                                               onChange={e => setSelectedRegion(e.target.value)}
                                               className="w-full px-4 py-2 bg-gray-700 border border-gray-600 rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none text-white"
                                               required
                                           >
                                               <option value="">Seleziona Regione...</option>
                                               {Object.keys(UNIVERSITY_LOCATIONS).map(r => (
                                                   <option key={r} value={r}>{r}</option>
                                               ))}
                                           </select>
                                       </div>
                                   </div>
                               </div>

                               <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                                   <div>
                                       <label className="block text-sm font-medium text-gray-300 mb-1 flex items-center"><MapPin className="w-4 h-4 mr-1 text-indigo-400"/> Città Universitaria</label>
                                       <select 
                                           value={city}
                                           onChange={e => setCity(e.target.value)}
                                           className={`w-full px-4 py-2 bg-gray-700 border border-gray-600 rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none text-white ${!selectedRegion ? 'opacity-50 cursor-not-allowed' : ''}`}
                                           required
                                           disabled={!selectedRegion}
                                       >
                                           <option value="">{selectedRegion ? 'Seleziona Città...' : 'Scegli prima una regione'}</option>
                                           {selectedRegion && UNIVERSITY_LOCATIONS[selectedRegion].map(c => (
                                               <option key={c} value={c}>{c}</option>
                                           ))}
                                       </select>
                                   </div>
                                   <div>
                                       <label className="block text-sm font-medium text-gray-300 mb-1">Indirizzo Specifico (Location)</label>
                                       <input 
                                           type="text" 
                                           value={location} 
                                           onChange={e => setLocation(e.target.value)} 
                                           className="w-full px-4 py-2 bg-gray-700 border border-gray-600 rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none text-white placeholder-gray-400"
                                           required
                                           placeholder="Es. Via Roma 123, locale X"
                                       />
                                   </div>
                               </div>

                               <div>
                                   <label className="block text-sm font-medium text-gray-300 mb-1 flex items-center"><ImageIcon className="w-4 h-4 mr-1 text-indigo-400"/> Immagine Evento</label>
                                   <div className="flex gap-4 items-center">
                                       <button
                                           type="button"
                                           onClick={handleImageUpload}
                                           className="flex items-center px-4 py-2.5 bg-gray-700 text-gray-200 rounded-lg hover:bg-gray-600 transition font-medium border border-gray-600"
                                       >
                                           <Upload className="w-4 h-4 mr-2" />
                                           Carica Immagine
                                       </button>
                                       {image && (
                                           <div className="w-16 h-10 rounded-lg overflow-hidden border border-gray-600 flex-shrink-0 relative group">
                                               <img src={image} alt="Preview" className="w-full h-full object-cover" onError={(e) => (e.currentTarget.style.display = 'none')} />
                                           </div>
                                       )}
                                   </div>
                               </div>

                               {/* Impostazioni Avanzate */}
                               <div className="grid grid-cols-1 md:grid-cols-2 gap-6 p-4 bg-gray-900/30 rounded-xl border border-gray-700">
                                   <div className="flex items-center space-x-3">
                                       <input 
                                           type="checkbox" 
                                           id="reqAcademicData"
                                           checked={requiresAcademicData}
                                           onChange={e => setRequiresAcademicData(e.target.checked)}
                                           className="h-5 w-5 text-indigo-600 focus:ring-indigo-500 bg-gray-700 border-gray-600 rounded"
                                       />
                                       <label htmlFor="reqAcademicData" className="text-sm text-gray-300 font-medium cursor-pointer flex items-center">
                                           <GraduationCap className="w-4 h-4 mr-2 text-indigo-400" />
                                           Richiedi Dati Accademici (Matricola e Corso)
                                       </label>
                                   </div>
                                   <div>
                                       <label className="block text-sm font-medium text-gray-300 mb-1">Tipo di Scansione</label>
                                       <select 
                                           value={scanType}
                                           onChange={e => setScanType(e.target.value as any)}
                                           className="w-full px-4 py-2 bg-gray-700 border border-gray-600 rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none text-white"
                                       >
                                           <option value="entry_only">Solo Entrata (Classic)</option>
                                           <option value="entry_exit">Entrata + Uscita (Monitoraggio Tempo)</option>
                                       </select>
                                   </div>
                               </div>

                               <div className="grid grid-cols-1 md:grid-cols-2 gap-6 p-4 bg-gray-900/50 rounded-xl border border-gray-700">
                                   <div className="relative">
                                       <label className="block text-sm font-medium text-gray-300 mb-1 flex items-center">
                                           <DollarSign className="w-4 h-4 mr-1 text-indigo-400"/> Prezzo Biglietto (€)
                                       </label>
                                       <div className="relative">
                                            <input 
                                                type="number" 
                                                value={user.stripeOnboardingComplete ? price : '0'} 
                                                onChange={e => {
                                                    if (user.stripeOnboardingComplete) setPrice(e.target.value);
                                                }} 
                                                disabled={!user.stripeOnboardingComplete}
                                                className={`w-full px-4 py-2 border rounded-lg outline-none transition
                                                    ${!user.stripeOnboardingComplete 
                                                        ? 'bg-gray-800 text-gray-500 border-gray-700 cursor-not-allowed' 
                                                        : 'bg-gray-700 border-gray-600 focus:ring-2 focus:ring-indigo-500 text-white'
                                                    }
                                                `}
                                                required
                                                min="0"
                                                step="0.01"
                                                placeholder="0.00"
                                            />
                                            {!user.stripeOnboardingComplete && (
                                                <div className="absolute inset-y-0 right-0 pr-3 flex items-center pointer-events-none">
                                                    <Lock className="h-4 w-4 text-gray-500" />
                                                </div>
                                            )}
                                       </div>
                                   </div>
                                   <div>
                                       <label className="block text-sm font-medium text-gray-300 mb-1 flex items-center"><Users className="w-4 h-4 mr-1 text-indigo-400"/> Capacità Massima</label>
                                       <input 
                                           type="number" 
                                           value={maxCapacity} 
                                           onChange={e => setMaxCapacity(e.target.value)} 
                                           className="w-full px-4 py-2 bg-gray-700 border border-gray-600 rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none text-white"
                                           required
                                           min="1"
                                       />
                                   </div>
                               </div>

                               <div className="pt-4 flex gap-4">
                                   <button 
                                       type="submit" 
                                       onClick={() => setTargetStatus('draft')}
                                       disabled={creatingEvent}
                                       className="flex-1 bg-gray-700 hover:bg-gray-600 text-gray-200 font-bold py-4 rounded-xl shadow-md transition border border-gray-600"
                                   >
